class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode() {}
    TreeNode(int val) { this.val = val; }
    TreeNode(int val, TreeNode left, TreeNode right) {
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

class Solution {
    public boolean isCousins(TreeNode root, int x, int y) {
        int xDepth = findDepth(root, x, 0);
        int yDepth = findDepth(root, y, 0);
        TreeNode xParent = findParent(root, x);
        TreeNode yParent = findParent(root, y);
        return (xDepth == yDepth) && (xParent != yParent);
    }

    private int findDepth(TreeNode node, int searchVal, int depth) {
        if (node == null) return -1;
        if (node.val == searchVal) return depth;
        int leftDepth = findDepth(node.left, searchVal, depth + 1);
        if (leftDepth != -1) return leftDepth;
        return findDepth(node.right, searchVal, depth + 1);
    }

    private TreeNode findParent(TreeNode node, int searchVal) {
        if (node == null || (node.left == null && node.right == null)) return null;
        if ((node.left != null && node.left.val == searchVal) || (node.right != null && node.right.val == searchVal)) return node;
        TreeNode leftParent = findParent(node.left, searchVal);
        if (leftParent != null) return leftParent;
        return findParent(node.right, searchVal);
    }
}
